const item = $input.item;
// Rename binary to audio.ogg so Groq accepts it
if (item.binary && item.binary.data) {
  item.binary.data.fileName = 'audio.ogg';
  item.binary.data.mimeType = 'audio/ogg';
}
return item;

const transcription = $json.text;
const telegramText = $json.message?.text;
const inputChatId = $('Telegram Trigger-or').first()?.json?.message?.chat?.id || "internal_chat";

return {
    message: {
      text: transcription || telegramText || '',
      chat: { id: inputChatId }
    },
    text: transcription || telegramText || ''
};

const now = $now.setZone('America/Argentina/Buenos_Aires');

const hour = now.hour;

let saludo;

if (hour < 13) {
  saludo = "Buen día";
} else if (hour < 20) {
  saludo = "Buenas tardes";
} else {
  saludo = "Buenas noches";
}

return {
  json: {
    // Pass through original data
    ...($json || {}),
    text: $json.text || $json.message?.text || '',
    message: $json.message || {},
    // Inject calculated values
    saludo: saludo,
    fecha_actual: now.toFormat("cccc dd/MM/yyyy HH:mm"),
    fecha_iso: now.toFormat("yyyy-MM-dd"),
    hora_actual: now.toFormat("HH:mm"),
    año_actual: now.toFormat("yyyy")
  }
};

// Obtener mensaje original del input
const originalMessage = $input.item.json.message || {};
const textFromMessage = originalMessage.text || '';

// Extraer transcripción si existe
const transcription = $json.transcription || '';

// Crear el texto final
const finalText = transcription || textFromMessage;

return {
  json: {
    text: finalText,
    message: originalMessage
  }
};

